import javax.annotation.PostConstruct;
import java.util.Arrays;
import java.util.Collections;
import java.util.List;

@Configuration
public class OpenSamlConfig {

    private static final List<String> ALLOWED_SIGNATURE_ALGORITHMS = Collections.unmodifiableList(Arrays.asList(
            SignatureConstants.ALGO_ID_SIGNATURE_RSA_SHA256,
            SignatureConstants.ALGO_ID_SIGNATURE_RSA_SHA384,
            SignatureConstants.ALGO_ID_SIGNATURE_RSA_SHA512,
            SignatureConstants.ALGO_ID_SIGNATURE_ECDSA_SHA256,
            SignatureConstants.ALGO_ID_SIGNATURE_ECDSA_SHA384,
            SignatureConstants.ALGO_ID_SIGNATURE_ECDSA_SHA512
    ));

    private static final List<String> BLOCKED_SIGNATURE_ALGORITHMS = Collections.unmodifiableList(Arrays.asList(
            SignatureConstants.ALGO_ID_SIGNATURE_RSA_SHA1,
            SignatureConstants.ALGO_ID_SIGNATURE_NOT_RECOMMENDED_RSA_MD5,
            SignatureConstants.ALGO_ID_DIGEST_SHA1,
            SignatureConstants.ALGO_ID_MAC_HMAC_SHA1
    ));

    @PostConstruct
    public void initOpenSaml() throws InitializationException {
        XMLObjectProviderRegistry registry = new XMLObjectProviderRegistry();
        ConfigurationService.register(XMLObjectProviderRegistry.class, registry);
        InitializationService.initialize();
    }

    @Bean
    public BasicSignatureValidationConfiguration signatureValidationConfiguration() {
        BasicSignatureValidationConfiguration config = DefaultSecurityConfigurationBootstrap
                .buildDefaultSignatureValidationConfiguration();
        config.setExcludedAlgorithms(BLOCKED_SIGNATURE_ALGORITHMS);
        config.setIncludedAlgorithms(ALLOWED_SIGNATURE_ALGORITHMS);
        return config;
    }

    public static List<String> getAllowedSignatureAlgorithms() {
        return ALLOWED_SIGNATURE_ALGORITHMS;
    }

    public static List<String> getBlockedSignatureAlgorithms() {
        return BLOCKED_SIGNATURE_ALGORITHMS;
    }
}

