package com.example.samlsp.credential;

import com.example.samlsp.config.SamlProperties;
import org.opensaml.security.credential.Credential;
import org.opensaml.security.credential.impl.KeyStoreCredentialResolver;
import org.opensaml.security.x509.BasicX509Credential;
import org.opensaml.security.x509.X509Credential;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.core.io.ClassPathResource;
import org.springframework.core.io.Resource;
import org.springframework.stereotype.Component;

import javax.annotation.PostConstruct;
import java.io.ByteArrayInputStream;
import java.io.InputStream;
import java.nio.file.Files;
import java.nio.file.Paths;
import java.security.KeyStore;
import java.security.PrivateKey;
import java.security.cert.CertificateFactory;
import java.security.cert.X509Certificate;
import java.util.Collections;
import java.util.HashMap;
import java.util.Map;

@Component
public class KeyStoreCredentialManager {

    private static final Logger logger = LoggerFactory.getLogger(KeyStoreCredentialManager.class);

    @Autowired
    private SamlProperties samlProperties;

    private X509Credential spCredential;
    private X509Credential idpCredential;

    @PostConstruct
    public void init() throws Exception {
        loadSpCredential();
        loadIdpCredential();
    }

    private void loadSpCredential() throws Exception {
        KeyStore keyStore = KeyStore.getInstance("JKS");
        Resource resource = new ClassPathResource(samlProperties.getSpKeystorePath());
        try (InputStream is = resource.getInputStream()) {
            keyStore.load(is, samlProperties.getSpKeystorePassword().toCharArray());
        }

        Map<String, String> passwordMap = new HashMap<>();
        passwordMap.put(samlProperties.getSpKeyAlias(), samlProperties.getSpKeyPassword());

        KeyStoreCredentialResolver resolver = new KeyStoreCredentialResolver(keyStore, passwordMap);
        Credential credential = resolver.resolveSingle(
                new org.opensaml.security.criteria.UsageCriteria(
                        org.opensaml.security.credential.UsageType.SIGNING));

        if (credential == null) {
            // Fallback: load directly from keystore
            X509Certificate cert = (X509Certificate) keyStore.getCertificate(samlProperties.getSpKeyAlias());
            PrivateKey privateKey = (PrivateKey) keyStore.getKey(
                    samlProperties.getSpKeyAlias(),
                    samlProperties.getSpKeyPassword().toCharArray());

            if (cert == null || privateKey == null) {
                throw new IllegalStateException("SP certificate or private key not found in keystore");
            }

            BasicX509Credential basicCredential = new BasicX509Credential(cert, privateKey);
            basicCredential.setEntityId(samlProperties.getEntityId());
            this.spCredential = basicCredential;
        } else {
            this.spCredential = (X509Credential) credential;
        }

        logger.info("SP credential loaded successfully for entity: {}", samlProperties.getEntityId());
    }

    private void loadIdpCredential() throws Exception {
        String certPath = samlProperties.getIdpCertificatePath();
        byte[] certBytes;

        Resource resource = new ClassPathResource(certPath);
        if (resource.exists()) {
            try (InputStream is = resource.getInputStream()) {
                certBytes = is.readAllBytes();
            }
        } else {
            certBytes = Files.readAllBytes(Paths.get(certPath));
        }

        CertificateFactory cf = CertificateFactory.getInstance("X.509");
        X509Certificate idpCert = (X509Certificate) cf.generateCertificate(new ByteArrayInputStream(certBytes));

        // Validate certificate is not expired
        idpCert.checkValidity();

        BasicX509Credential basicCredential = new BasicX509Credential(idpCert);
        basicCredential.setEntityId(samlProperties.getIdpEntityId());
        this.idpCredential = basicCredential;

        logger.info("IdP credential loaded successfully for entity: {}", samlProperties.getIdpEntityId());
    }

    public X509Credential getSpCredential() {
        return spCredential;
    }

    public X509Credential getIdpCredential() {
        return idpCredential;
    }
}

