package com.example.samlsp.service;

import com.example.samlsp.config.SamlProperties;
import com.example.samlsp.credential.KeyStoreCredentialManager;
import org.joda.time.DateTime;
import org.opensaml.core.xml.XMLObjectBuilderFactory;
import org.opensaml.core.xml.config.XMLObjectProviderRegistrySupport;
import org.opensaml.saml.common.SAMLVersion;
import org.opensaml.saml.saml2.core.*;
import org.opensaml.saml.saml2.core.impl.*;
import org.opensaml.xmlsec.signature.Signature;
import org.opensaml.xmlsec.signature.impl.SignatureBuilder;
import org.opensaml.xmlsec.signature.support.SignatureConstants;
import org.opensaml.xmlsec.signature.support.Signer;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;

import java.security.SecureRandom;
import java.util.Base64;
import java.util.UUID;

@Service
public class SamlMessageBuilder {

    private static final Logger logger = LoggerFactory.getLogger(SamlMessageBuilder.class);
    private static final SecureRandom SECURE_RANDOM = new SecureRandom();

    @Autowired
    private SamlProperties samlProperties;

    @Autowired
    private KeyStoreCredentialManager credentialManager;

    public AuthnRequest buildAuthnRequest(String relayState) throws Exception {
        AuthnRequestBuilder authnRequestBuilder = new AuthnRequestBuilder();
        AuthnRequest authnRequest = authnRequestBuilder.buildObject();

        authnRequest.setID(generateSecureId());
        authnRequest.setVersion(SAMLVersion.VERSION_20);
        authnRequest.setIssueInstant(new DateTime());
        authnRequest.setDestination(samlProperties.getIdpSsoUrl());
        authnRequest.setProtocolBinding("urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST");
        authnRequest.setAssertionConsumerServiceURL(samlProperties.getAcsUrl());
        authnRequest.setForceAuthn(samlProperties.isForceAuthn());
        authnRequest.setIsPassive(false);

        // Set Issuer
        IssuerBuilder issuerBuilder = new IssuerBuilder();
        Issuer issuer = issuerBuilder.buildObject();
        issuer.setValue(samlProperties.getEntityId());
        authnRequest.setIssuer(issuer);

        // Set NameIDPolicy
        NameIDPolicyBuilder nameIdPolicyBuilder = new NameIDPolicyBuilder();
        NameIDPolicy nameIdPolicy = nameIdPolicyBuilder.buildObject();
        nameIdPolicy.setFormat("urn:oasis:names:tc:SAML:2.0:nameid-format:transient");
        nameIdPolicy.setAllowCreate(true);
        authnRequest.setNameIDPolicy(nameIdPolicy);

        // Set RequestedAuthnContext
        RequestedAuthnContextBuilder requestedAuthnContextBuilder = new RequestedAuthnContextBuilder();
        RequestedAuthnContext requestedAuthnContext = requestedAuthnContextBuilder.buildObject();
        requestedAuthnContext.setComparison(AuthnContextComparisonTypeEnumeration.MINIMUM);

        AuthnContextClassRefBuilder authnContextClassRefBuilder = new AuthnContextClassRefBuilder();
        AuthnContextClassRef authnContextClassRef = authnContextClassRefBuilder.buildObject();
        authnContextClassRef.setURI("urn:oasis:names:tc:SAML:2.0:ac:classes:PasswordProtectedTransport");
        requestedAuthnContext.getAuthnContextClassRefs().add(authnContextClassRef);
        authnRequest.setRequestedAuthnContext(requestedAuthnContext);

        // Sign the AuthnRequest using SHA-256
        signSamlObject(authnRequest);

        logger.info("AuthnRequest built with ID: {}", authnRequest.getID());
        return authnRequest;
    }

    public LogoutRequest buildLogoutRequest(String nameId, String sessionIndex) throws Exception {
        LogoutRequestBuilder logoutRequestBuilder = new LogoutRequestBuilder();
        LogoutRequest logoutRequest = logoutRequestBuilder.buildObject();

        logoutRequest.setID(generateSecureId());
        logoutRequest.setVersion(SAMLVersion.VERSION_20);
        logoutRequest.setIssueInstant(new DateTime());
        logoutRequest.setDestination(samlProperties.getIdpSloUrl());
        logoutRequest.setNotOnOrAfter(new DateTime().plusMinutes(5));

        // Set Issuer
        IssuerBuilder issuerBuilder = new IssuerBuilder();
        Issuer issuer = issuerBuilder.buildObject();
        issuer.setValue(samlProperties.getEntityId());
        logoutRequest.setIssuer(issuer);

        // Set NameID
        NameIDBuilder nameIdBuilder = new NameIDBuilder();
        NameID nameID = nameIdBuilder.buildObject();
        nameID.setValue(nameId);
        nameID.setFormat("urn:oasis:names:tc:SAML:2.0:nameid-format:transient");
        logoutRequest.setNameID(nameID);

        // Set SessionIndex
        if (sessionIndex != null) {
            SessionIndexBuilder sessionIndexBuilder = new SessionIndexBuilder();
            SessionIndex sessionIdx = sessionIndexBuilder.buildObject();
            sessionIdx.setValue(sessionIndex);
            logoutRequest.getSessionIndexes().add(sessionIdx);
        }

        // Sign the LogoutRequest
        signSamlObject(logoutRequest);

        logger.info("LogoutRequest built with ID: {}", logoutRequest.getID());
        return logoutRequest;
    }

    private void signSamlObject(org.opensaml.saml.common.SignableSAMLObject samlObject) throws Exception {
        SignatureBuilder signatureBuilder = new SignatureBuilder();
        Signature signature = signatureBuilder.buildObject();
        signature.setSigningCredential(credentialManager.getSpCredential());
        signature.setSignatureAlgorithm(SignatureConstants.ALGO_ID_SIGNATURE_RSA_SHA256);
        signature.setCanonicalizationAlgorithm(SignatureConstants.ALGO_ID_C14N_EXCL_OMIT_COMMENTS);

        samlObject.setSignature(signature);

        XMLObjectProviderRegistrySupport.getMarshallerFactory()
                .getMarshaller(samlObject)
                .marshall(samlObject);

        Signer.signObject(signature);
    }

    private String generateSecureId() {
        byte[] randomBytes = new byte[20];
        SECURE_RANDOM.nextBytes(randomBytes);
        return "_" + Base64.getUrlEncoder().withoutPadding().encodeToString(randomBytes);
    }
}

