import com.example.samlsp.credential.KeyStoreCredentialManager;
import com.example.samlsp.model.SamlAuthenticationToken;
import org.joda.time.DateTime;
import org.opensaml.core.xml.XMLObject;
import org.opensaml.core.xml.config.XMLObjectProviderRegistrySupport;
import org.opensaml.core.xml.io.Unmarshaller;
import org.opensaml.core.xml.io.UnmarshallerFactory;
import org.opensaml.saml.saml2.core.*;
import org.opensaml.saml.saml2.encryption.Decrypter;
import org.opensaml.security.credential.Credential;
import org.opensaml.xmlsec.encryption.support.InlineEncryptedKeyResolver;
import org.opensaml.xmlsec.keyinfo.impl.StaticKeyInfoCredentialResolver;
import org.opensaml.xmlsec.signature.Signature;
import org.opensaml.xmlsec.signature.support.SignatureValidator;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;
import org.w3c.dom.Document;
import org.w3c.dom.Element;

import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import java.io.ByteArrayInputStream;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;

@Service
public class SamlResponseValidator {

    private static final Logger logger = LoggerFactory.getLogger(SamlResponseValidator.class);

    @Autowired
    private SamlProperties samlProperties;

    @Autowired
    private KeyStoreCredentialManager credentialManager;

    // Replay attack prevention: store processed response IDs with expiration
    private final ConcurrentHashMap<String, Long> processedResponseIds = new ConcurrentHashMap<>();
    private static final long RESPONSE_ID_EXPIRY_MS = 3600000; // 1 hour

    public SamlAuthenticationToken validateResponse(String samlResponseBase64) throws Exception {
        // Clean up expired entries
        cleanupExpiredResponseIds();

        byte[] decodedResponse = Base64.getDecoder().decode(samlResponseBase64);

        // Parse XML securely - prevent XXE attacks
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        factory.setNamespaceAware(true);
        // Disable external entities to prevent XXE
        factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
        factory.setXIncludeAware(false);
        factory.setExpandEntityReferences(false);

        DocumentBuilder builder = factory.newDocumentBuilder();
        Document document = builder.parse(new ByteArrayInputStream(decodedResponse));
        Element element = document.getDocumentElement();

        UnmarshallerFactory unmarshallerFactory = XMLObjectProviderRegistrySupport.getUnmarshallerFactory();
        Unmarshaller unmarshaller = unmarshallerFactory.getUnmarshaller(element);

        if (unmarshaller == null) {
            throw new SecurityException("Unable to obtain unmarshaller for SAML response element");
        }

        XMLObject xmlObject = unmarshaller.unmarshall(element);

        if (!(xmlObject instanceof Response)) {
            throw new SecurityException("Unmarshalled object is not a SAML Response");
        }

        Response response = (Response) xmlObject;

        // Validate response
        validateResponseStructure(response);
        validateResponseSignature(response);
        validateResponseStatus(response);
        validateResponseDestination(response);
        validateResponseIssuer(response);
        checkReplayAttack(response);

        // Process assertions
        Assertion assertion = getValidAssertion(response);
        validateAssertionSignature(assertion);
        validateAssertionConditions(assertion);
        validateAssertionSubject(assertion);
        validateAssertionAuthnStatements(assertion);

        // Extract authentication information
        return extractAuthenticationToken(assertion);
    }

    private void validateResponseStructure(Response response) throws SecurityException {
        if (response.getID() == null || response.getID().isEmpty()) {
            throw new SecurityException("SAML Response ID is missing");
        }

        if (response.getVersion() == null || !response.getVersion().equals(org.opensaml.saml.common.SAMLVersion.VERSION_20)) {
            throw new SecurityException("Invalid SAML version");
        }

        if (response.getIssueInstant() == null) {
            throw new SecurityException("SAML Response IssueInstant is missing");
        }

        // Validate IssueInstant is not too old or in the future
        DateTime now = new DateTime();
        DateTime issueInstant = response.getIssueInstant();
        int skew = samlProperties.getResponseSkew();

        if (issueInstant.isBefore(now.minusSeconds(samlProperties.getMaxAuthenticationAge()))) {
            throw new SecurityException("SAML Response IssueInstant is too old");
        }

        if (issueInstant.isAfter(now.plusSeconds(skew))) {
            throw new SecurityException("SAML Response IssueInstant is in the future");
        }
    }

    private void validateResponseSignature(Response response) throws Exception {
        if (samlProperties.isWantResponseSigned()) {
            Signature signature = response.getSignature();
            if (signature == null) {
                throw new SecurityException("SAML Response is not signed but signature is required");
            }

            // Validate signature algorithm is not weak
            String signatureAlgorithm = signature.getSignatureAlgorithm();
            if (signatureAlgorithm != null && OpenSamlConfig.getBlockedSignatureAlgorithms().contains(signatureAlgorithm)) {
                throw new SecurityException("SAML Response uses a blocked signature algorithm: " + signatureAlgorithm);
            }

            if (signatureAlgorithm != null && !OpenSamlConfig.getAllowedSignatureAlgorithms().contains(signatureAlgorithm)) {
                throw new SecurityException("SAML Response uses an unsupported signature algorithm: " + signatureAlgorithm);
            }

            Credential idpCredential = credentialManager.getIdpCredential();
            SignatureValidator.validate(signature, idpCredential);
            logger.debug("SAML Response signature validated successfully");
        }
    }

    private void validateResponseStatus(Response response) throws SecurityException {
        Status status = response.getStatus();
        if (status == null || status.getStatusCode() == null) {
            throw new SecurityException("SAML Response status is missing");
        }

        String statusCode = status.getStatusCode().getValue();
        if (!StatusCode.SUCCESS.equals(statusCode)) {
            String statusMessage = status.getStatusMessage() != null ?
                    status.getStatusMessage().getValue() : "Unknown";
            throw new SecurityException("SAML authentication failed with status: " + statusCode +
                    ", message: " + statusMessage);
        }
    }

    private void validateResponseDestination(Response response) throws SecurityException {
        String destination = response.getDestination();
        if (destination != null && !destination.equals(samlProperties.getAcsUrl())) {
            throw new SecurityException("SAML Response destination mismatch. Expected: " +
                    samlProperties.getAcsUrl() + ", Got: " + destination);
        }
    }

    private void validateResponseIssuer(Response response) throws SecurityException {
        Issuer issuer = response.getIssuer();
        if (issuer == null || issuer.getValue() == null) {
            throw new SecurityException("SAML Response issuer is missing");
        }

        if (!samlProperties.getIdpEntityId().equals(issuer.getValue())) {
            throw new SecurityException("SAML Response issuer mismatch. Expected: " +
                    samlProperties.getIdpEntityId() + ", Got: " + issuer.getValue());
        }
    }

    private void checkReplayAttack(Response response) throws SecurityException {
        String responseId = response.getID();
        Long existingTimestamp = processedResponseIds.putIfAbsent(responseId, System.currentTimeMillis());
        if (existingTimestamp != null) {
            throw new SecurityException("Replay attack detected: SAML Response ID already processed: " + responseId);
        }
    }

    private Assertion getValidAssertion(Response response) throws Exception {
        List<Assertion> assertions = response.getAssertions();
        List<EncryptedAssertion> encryptedAssertions = response.getEncryptedAssertions();

        // Decrypt encrypted assertions if present
        if (encryptedAssertions != null && !encryptedAssertions.isEmpty()) {
            StaticKeyInfoCredentialResolver keyInfoResolver =
                    new StaticKeyInfoCredentialResolver(credentialManager.getSpCredential());
            Decrypter decrypter = new Decrypter(null, keyInfoResolver, new InlineEncryptedKeyResolver());
            decrypter.setRootInNewDocument(true);

            for (EncryptedAssertion encryptedAssertion : encryptedAssertions) {
                Assertion decryptedAssertion = decrypter.decrypt(encryptedAssertion);
                assertions.add(decryptedAssertion);
            }
        }

        if (assertions == null || assertions.isEmpty()) {
            throw new SecurityException("No assertions found in SAML Response");
        }

        // Return the first valid assertion
        return assertions.get(0);
    }

    private void validateAssertionSignature(Assertion assertion) throws Exception {
        if (samlProperties.isWantAssertionsSigned()) {
            Signature signature = assertion.getSignature();
            if (signature == null) {
                throw new SecurityException("SAML Assertion is not signed but signature is required");
            }

            // Validate signature algorithm
            String signatureAlgorithm = signature.getSignatureAlgorithm();
            if (signatureAlgorithm != null && OpenSamlConfig.getBlockedSignatureAlgorithms().contains(signatureAlgorithm)) {
                throw new SecurityException("SAML Assertion uses a blocked signature algorithm: " + signatureAlgorithm);
            }

            if (signatureAlgorithm != null && !OpenSamlConfig.getAllowedSignatureAlgorithms().contains(signatureAlgorithm)) {
                throw new SecurityException("SAML Assertion uses an unsupported signature algorithm: " + signatureAlgorithm);
            }

            Credential idpCredential = credentialManager.getIdpCredential();
            SignatureValidator.validate(signature, idpCredential);
            logger.debug("SAML Assertion signature validated successfully");
        }
    }

    private void validateAssertionConditions(Assertion assertion) throws SecurityException {
        Conditions conditions = assertion.getConditions();
        if (conditions == null) {
            throw new SecurityException("SAML Assertion conditions are missing");
        }

        DateTime now = new DateTime();
        int skew = samlProperties.getResponseSkew();

        // Validate NotBefore
        if (conditions.getNotBefore() != null) {
            if (now.plusSeconds(skew).isBefore(conditions.getNotBefore())) {
                throw new SecurityException("SAML Assertion is not yet valid (NotBefore condition)");
            }
        }

        // Validate NotOnOrAfter
        if (conditions.getNotOnOrAfter() != null) {
            if (now.minusSeconds(skew).isAfter(conditions.getNotOnOrAfter())) {
                throw new SecurityException("SAML Assertion has expired (NotOnOrAfter condition)");
            }
        }

        // Validate AudienceRestriction
        List<AudienceRestriction> audienceRestrictions = conditions.getAudienceRestrictions();
        if (audienceRestrictions == null || audienceRestrictions.isEmpty()) {
            throw new SecurityException("SAML Assertion AudienceRestriction is missing");
        }

        boolean audienceValid = false;
        for (AudienceRestriction restriction : audienceRestrictions) {
            for (Audience audience : restriction.getAudiences()) {
                if (samlProperties.getEntityId().equals(audience.getURI())) {
                    audienceValid = true;
                    break;
                }
            }
            if (audienceValid) break;
        }

        if (!audienceValid) {
            throw new SecurityException("SAML Assertion audience does not match SP entity ID: " +
                    samlProperties.getEntityId());
        }
    }

    private void validateAssertionSubject(Assertion assertion) throws SecurityException {
        Subject subject = assertion.getSubject();
        if (subject == null) {
            throw new SecurityException("SAML Assertion subject is missing");
        }

        List<SubjectConfirmation> confirmations = subject.getSubjectConfirmations();
        if (confirmations == null || confirmations.isEmpty()) {
            throw new SecurityException("SAML Assertion SubjectConfirmation is missing");
        }

        boolean validConfirmation = false;
        DateTime now = new DateTime();
        int skew = samlProperties.getResponseSkew();

        for (SubjectConfirmation confirmation : confirmations) {
            if (!"urn:oasis:names:tc:SAML:2.0:cm:bearer".equals(confirmation.getMethod())) {
                continue;
            }

            SubjectConfirmationData data = confirmation.getSubjectConfirmationData();
            if (data == null) {
                continue;
            }

            // Validate Recipient
            if (data.getRecipient() != null && !samlProperties.getAcsUrl().equals(data.getRecipient())) {
                logger.warn("SubjectConfirmation recipient mismatch: {}", data.getRecipient());
                continue;
            }

            // Validate NotOnOrAfter
            if (data.getNotOnOrAfter() != null && now.minusSeconds(skew).isAfter(data.getNotOnOrAfter())) {
                logger.warn("SubjectConfirmation has expired");
                continue;
            }

            // Validate NotBefore
            if (data.getNotBefore() != null && now.plusSeconds(skew).isBefore(data.getNotBefore())) {
                logger.warn("SubjectConfirmation is not yet valid");
                continue;
            }

            validConfirmation = true;
            break;
        }

        if (!validConfirmation) {
            throw new SecurityException("No valid SubjectConfirmation found in SAML Assertion");
        }
    }

    private void validateAssertionAuthnStatements(Assertion assertion) throws SecurityException {
        List<AuthnStatement> authnStatements = assertion.getAuthnStatements();
        if (authnStatements == null || authnStatements.isEmpty()) {
            throw new SecurityException("SAML Assertion AuthnStatement is missing");
        }

        DateTime now = new DateTime();
        for (AuthnStatement authnStatement : authnStatements) {
            // Validate AuthnInstant
            if (authnStatement.getAuthnInstant() != null) {
                DateTime authnInstant = authnStatement.getAuthnInstant();
                if (authnInstant.isBefore(now.minusSeconds(samlProperties.getMaxAuthenticationAge()))) {
                    throw new SecurityException("Authentication is too old");
                }
            }

            // Validate SessionNotOnOrAfter
            if (authnStatement.getSessionNotOnOrAfter() != null) {
                if (now.isAfter(authnStatement.getSessionNotOnOrAfter())) {
                    throw new SecurityException("SAML session has expired");
                }
            }
        }
    }

    private SamlAuthenticationToken extractAuthenticationToken(Assertion assertion) {
        String nameId = null;
        String nameIdFormat = null;
        String sessionIndex = null;
        Map<String, List<String>> attributes = new HashMap<>();

        // Extract NameID
        Subject subject = assertion.getSubject();
        if (subject != null && subject.getNameID() != null) {
            nameId = subject.getNameID().getValue();
            nameIdFormat = subject.getNameID().getFormat();
        }

        // Extract SessionIndex
        List<AuthnStatement> authnStatements = assertion.getAuthnStatements();
        if (authnStatements != null && !authnStatements.isEmpty()) {
            sessionIndex = authnStatements.get(0).getSessionIndex();
        }

        // Extract Attributes
        List<AttributeStatement> attributeStatements = assertion.getAttributeStatements();
        if (attributeStatements != null) {
            for (AttributeStatement attributeStatement : attributeStatements) {
                for (Attribute attribute : attributeStatement.getAttributes()) {
                    String attrName = attribute.getName();
                    List<String> values = new ArrayList<>();
                    for (XMLObject value : attribute.getAttributeValues()) {
                        if (value.getDOM() != null) {
                            values.add(value.getDOM().getTextContent());
                        }
                    }
                    attributes.put(attrName, values);
                }
            }
        }

        if (nameId == null || nameId.isEmpty()) {
            throw new SecurityException("NameID is missing from SAML Assertion");
        }

        return new SamlAuthenticationToken(nameId, nameIdFormat, sessionIndex, attributes);
    }

    private void cleanupExpiredResponseIds() {
        long now = System.currentTimeMillis();
        processedResponseIds.entrySet().removeIf(entry ->
                (now - entry.getValue()) > RESPONSE_ID_EXPIRY_MS);
    }
}

