package com.example.samlsp.model;

import org.springframework.security.authentication.AbstractAuthenticationToken;
import org.springframework.security.core.GrantedAuthority;
import org.springframework.security.core.authority.SimpleGrantedAuthority;

import java.util.*;

public class SamlAuthenticationToken extends AbstractAuthenticationToken {

    private final String nameId;
    private final String nameIdFormat;
    private final String sessionIndex;
    private final Map<String, List<String>> attributes;
    private final SamlUserPrincipal principal;

    public SamlAuthenticationToken(String nameId, String nameIdFormat, String sessionIndex,
                                    Map<String, List<String>> attributes) {
        super(buildAuthorities(attributes));
        this.nameId = nameId;
        this.nameIdFormat = nameIdFormat;
        this.sessionIndex = sessionIndex;
        this.attributes = Collections.unmodifiableMap(new HashMap<>(attributes));
        this.principal = new SamlUserPrincipal(nameId, nameIdFormat, attributes);
        setAuthenticated(true);
    }

    private static Collection<? extends GrantedAuthority> buildAuthorities(Map<String, List<String>> attributes) {
        List<GrantedAuthority> authorities = new ArrayList<>();
        authorities.add(new SimpleGrantedAuthority("ROLE_USER"));

        // Extract roles from attributes if present
        List<String> roles = attributes.get("roles");
        if (roles == null) {
            roles = attributes.get("Role");
        }
        if (roles == null) {
            roles = attributes.get("http://schemas.microsoft.com/ws/2008/06/identity/claims/role");
        }

        if (roles != null) {
            for (String role : roles) {
                String sanitizedRole = role.replaceAll("[^a-zA-Z0-9_]", "");
                if (!sanitizedRole.isEmpty()) {
                    authorities.add(new SimpleGrantedAuthority("ROLE_" + sanitizedRole.toUpperCase()));
                }
            }
        }

        return authorities;
    }

    @Override
    public Object getCredentials() {
        return null;
    }

    @Override
    public SamlUserPrincipal getPrincipal() {
        return principal;
    }

    public String getNameId() {
        return nameId;
    }

    public String getNameIdFormat() {
        return nameIdFormat;
    }

    public String getSessionIndex() {
        return sessionIndex;
    }

    public Map<String, List<String>> getAttributes() {
        return attributes;
    }
}

// ============================================================
// model/SamlUserPrincipal.java
// ============================================================
package com.example.samlsp.model;

import java.io.Serializable;
import java.security.Principal;
import java.util.Collections;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class SamlUserPrincipal implements Principal, Serializable {

    private static final long serialVersionUID = 1L;

    private final String nameId;
    private final String nameIdFormat;
    private final Map<String, List<String>> attributes;

    public SamlUserPrincipal(String nameId, String nameIdFormat, Map<String, List<String>> attributes) {
        this.nameId = nameId;
        this.nameIdFormat = nameIdFormat;
        this.attributes = Collections.unmodifiableMap(new HashMap<>(attributes));
    }

    @Override
    public String getName() {
        return nameId;
    }

    public String getNameId() {
        return nameId;
    }

    public String getNameIdFormat() {
        return nameIdFormat;
    }

    public Map<String, List<String>> getAttributes() {
        return attributes;
    }

    public String getAttribute(String name) {
        List<String> values = attributes.get(name);
        return (values != null && !values.isEmpty()) ? values.get(0) : null;
    }

    public List<String> getAttributeValues(String name) {
        return attributes.getOrDefault(name, Collections.emptyList());
    }

    @Override
    public String toString() {
        return "SamlUserPrincipal{nameId='" + nameId + "'}";
    }
}

