package com.example.samlsp.security;

import com.example.samlsp.model.SamlAuthenticationToken;
import com.example.samlsp.service.SamlResponseValidator;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.security.authentication.AuthenticationManager;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Component;
import org.springframework.web.filter.OncePerRequestFilter;

import javax.servlet.FilterChain;
import javax.servlet.ServletException;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import javax.servlet.http.HttpSession;
import java.io.IOException;

@Component
public class SamlAuthenticationFilter extends OncePerRequestFilter {

    private static final Logger logger = LoggerFactory.getLogger(SamlAuthenticationFilter.class);

    @Autowired
    private SamlResponseValidator samlResponseValidator;

    @Override
    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response,
                                     FilterChain filterChain) throws ServletException, IOException {

        if ("/saml/acs".equals(request.getRequestURI()) && "POST".equalsIgnoreCase(request.getMethod())) {
            String samlResponse = request.getParameter("SAMLResponse");

            if (samlResponse != null && !samlResponse.isEmpty()) {
                try {
                    SamlAuthenticationToken authToken = samlResponseValidator.validateResponse(samlResponse);

                    // Authenticate through the authentication manager
                    SecurityContextHolder.getContext().setAuthentication(authToken);

                    // Invalidate old session and create new one to prevent session fixation
                    HttpSession oldSession = request.getSession(false);
                    if (oldSession != null) {
                        oldSession.invalidate();
                    }
                    HttpSession newSession = request.getSession(true);
                    newSession.setMaxInactiveInterval(3600); // 1 hour

                    logger.info("SAML authentication successful for user: {}", authToken.getNameId());

                    // Redirect to home page after successful authentication
                    response.sendRedirect("/");
                    return;

                } catch (SecurityException e) {
                    logger.error("SAML authentication failed: {}", e.getMessage());
                    response.sendError(HttpServletResponse.SC_UNAUTHORIZED, "SAML Authentication Failed");
                    return;
                } catch (Exception e) {
                    logger.error("Error processing SAML response", e);
                    response.sendError(HttpServletResponse.SC_INTERNAL_SERVER_ERROR, "Error processing SAML response");
                    return;
                }
            }
        }

        filterChain.doFilter(request, response);
    }
}

