package com.example.samlsp.controller;

import com.example.samlsp.config.SamlProperties;
import com.example.samlsp.credential.KeyStoreCredentialManager;
import com.example.samlsp.model.SamlAuthenticationToken;
import com.example.samlsp.model.SamlUserPrincipal;
import com.example.samlsp.service.SamlMessageBuilder;
import com.example.samlsp.service.SamlMessageEncoder;
import org.opensaml.saml.saml2.core.AuthnRequest;
import org.opensaml.saml.saml2.core.LogoutRequest;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.ResponseBody;
import org.springframework.web.util.HtmlUtils;

import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import javax.servlet.http.HttpSession;
import java.io.UnsupportedEncodingException;
import java.net.URLEncoder;
import java.nio.charset.StandardCharsets;
import java.security.SecureRandom;
import java.util.Base64;

@Controller
@RequestMapping("/saml")
public class SamlController {

    private static final Logger logger = LoggerFactory.getLogger(SamlController.class);
    private static final SecureRandom SECURE_RANDOM = new SecureRandom();

    @Autowired
    private SamlProperties samlProperties;

    @Autowired
    private SamlMessageBuilder samlMessageBuilder;

    @Autowired
    private SamlMessageEncoder samlMessageEncoder;

    @Autowired
    private KeyStoreCredentialManager credentialManager;

    @GetMapping("/login")
    public void initiateLogin(HttpServletRequest request, HttpServletResponse response) throws Exception {
        // Generate RelayState for CSRF protection
        String relayState = generateRelayState();

        // Store RelayState in session
        HttpSession session = request.getSession(true);
        session.setAttribute("SAML_RELAY_STATE", relayState);

        AuthnRequest authnRequest = samlMessageBuilder.buildAuthnRequest(relayState);
        String encodedRequest = samlMessageEncoder.encodeRedirectMessage(authnRequest);

        StringBuilder redirectUrl = new StringBuilder(samlProperties.getIdpSsoUrl());
        redirectUrl.append("?SAMLRequest=").append(URLEncoder.encode(encodedRequest, StandardCharsets.UTF_8.name()));
        redirectUrl.append("&RelayState=").append(URLEncoder.encode(relayState, StandardCharsets.UTF_8.name()));

        logger.info("Redirecting to IdP for authentication");
        response.sendRedirect(redirectUrl.toString());
    }

    @GetMapping("/slo")
    public void initiateLogout(HttpServletRequest request, HttpServletResponse response) throws Exception {
        Authentication auth = SecurityContextHolder.getContext().getAuthentication();

        if (auth instanceof SamlAuthenticationToken) {
            SamlAuthenticationToken samlAuth = (SamlAuthenticationToken) auth;
            String nameId = samlAuth.getNameId();
            String sessionIndex = samlAuth.getSessionIndex();

            LogoutRequest logoutRequest = samlMessageBuilder.buildLogoutRequest(nameId, sessionIndex);
            String encodedRequest = samlMessageEncoder.encodeRedirectMessage(logoutRequest);

            // Clear security context
            SecurityContextHolder.clearContext();

            // Invalidate session
            HttpSession session = request.getSession(false);
            if (session != null) {
                session.invalidate();
            }

            StringBuilder redirectUrl = new StringBuilder(samlProperties.getIdpSloUrl());
            redirectUrl.append("?SAMLRequest=").append(URLEncoder.encode(encodedRequest, StandardCharsets.UTF_8.name()));

            logger.info("Redirecting to IdP for logout");
            response.sendRedirect(redirectUrl.toString());
        } else {
            // No SAML session, just redirect to login
            SecurityContextHolder.clearContext();
            HttpSession session = request.getSession(false);
            if (session != null) {
                session.invalidate();
            }
            response.sendRedirect("/saml/login");
        }
    }

    @GetMapping("/metadata")
    @ResponseBody
    public String getMetadata() throws Exception {
        return generateSpMetadata();
    }

    private String generateSpMetadata() {
        StringBuilder metadata = new StringBuilder();
        metadata.append("<?xml version=\"1.0\" encoding=\"UTF-8\"?>\n");
        metadata.append("<md:EntityDescriptor xmlns:md=\"urn:oasis:names:tc:SAML:2.0:metadata\" ");
        metadata.append("entityID=\"").append(HtmlUtils.htmlEscape(samlProperties.getEntityId())).append("\">\n");
        metadata.append("  <md:SPSSODescriptor AuthnRequestsSigned=\"true\" ");
        metadata.append("WantAssertionsSigned=\"").append(samlProperties.isWantAssertionsSigned()).append("\" ");
        metadata.append("protocolSupportEnumeration=\"urn:oasis:names:tc:SAML:2.0:protocol\">\n");

        // KeyDescriptor for signing
        try {
            java.security.cert.X509Certificate cert = credentialManager.getSpCredential().getEntityCertificate();
            String certBase64 = Base64.getEncoder().encodeToString(cert.getEncoded());

            metadata.append("    <md:KeyDescriptor use=\"signing\">\n");
            metadata.append("      <ds:KeyInfo xmlns:ds=\"http://www.w3.org/2000/09/xmldsig#\">\n");
            metadata.append("        <ds:X509Data>\n");
            metadata.append("          <ds:X509Certificate>").append(certBase64).append("</ds:X509Certificate>\n");
            metadata.append("        </ds:X509Data>\n");
            metadata.append("      </ds:KeyInfo>\n");
            metadata.append("    </md:KeyDescriptor>\n");

            // KeyDescriptor for encryption
            metadata.append("    <md:KeyDescriptor use=\"encryption\">\n");
            metadata.append("      <ds:KeyInfo xmlns:ds=\"http://www.w3.org/2000/09/xmldsig#\">\n");
            metadata.append("        <ds:X509Data>\n");
            metadata.append("          <ds:X509Certificate>").append(certBase64).append("</ds:X509Certificate>\n");
            metadata.append("        </ds:X509Data>\n");
            metadata.append("      </ds:KeyInfo>\n");
            metadata.append("    </md:KeyDescriptor>\n");
        } catch (Exception e) {
            logger.error("Error encoding SP certificate for metadata", e);
        }

        // NameIDFormat
        metadata.append("    <md:NameIDFormat>urn:oasis:names:tc:SAML:2.0:nameid-format:transient</md:NameIDFormat>\n");

        // AssertionConsumerService
        metadata.append("    <md:AssertionConsumerService ");
        metadata.append("Binding=\"urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST\" ");
        metadata.append("Location=\"").append(HtmlUtils.htmlEscape(samlProperties.getAcsUrl())).append("\" ");
        metadata.append("index=\"0\" isDefault=\"true\"/>\n");

        // SingleLogoutService
        metadata.append("    <md:SingleLogoutService ");
        metadata.append("Binding=\"urn:oasis:names:tc:SAML:2.0:bindings:HTTP-Redirect\" ");
        metadata.append("Location=\"").append(HtmlUtils.htmlEscape(samlProperties.getSloUrl())).append("\"/>\n");

        metadata.append("  </md:SPSSODescriptor>\n");
        metadata.append("</md:EntityDescriptor>");

        return metadata.toString();
    }

    private String generateRelayState() {
        byte[] randomBytes = new byte[32];
        SECURE_RANDOM.nextBytes(randomBytes);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(randomBytes);
    }
}

